const source = $input.first()?.json ?? {};
const now = new Date();
const yearText = new Intl.DateTimeFormat('en-GB', {
  timeZone: 'Europe/London',
  year: 'numeric',
}).format(now);
const defaultYear = Number.parseInt(yearText, 10);
const rawSeason = source.source_season ?? source.snapshot_year ?? source.year ?? defaultYear;
const sourceSeason = String(rawSeason).trim();
if (!/^\d{4}$/.test(sourceSeason)) {
  throw new Error('source_season must be a four-digit year');
}
const snapshotYear = Number.parseInt(sourceSeason, 10);
const nextSeason = String(snapshotYear + 1);
const snapshotKey = String(source.snapshot_key ?? `${sourceSeason}/${nextSeason}`).trim();
return [{
  json: {
    snapshot_key: snapshotKey,
    source_season: sourceSeason,
    contact_snapshot_year: snapshotYear
  }
}];

const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
};
const sqlInteger = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  const parsed = Number.parseInt(String(value), 10);
  if (Number.isNaN(parsed)) {
    throw new Error('contact_snapshot_year must be an integer');
  }
  return String(parsed);
};
const config = $input.first()?.json ?? {};
const sql = `WITH membership_capture AS (
  SELECT *
  FROM public.capture_membership_history_snapshot(${sqlLiteral(config.snapshot_key)}, ${sqlLiteral(config.source_season)})
), contact_capture AS (
  SELECT *
  FROM public.archive_raw_contacts_yearly_snapshot(${sqlInteger(config.contact_snapshot_year)})
)
SELECT
  m.snapshot_key,
  m.source_season,
  m.rows_written AS membership_rows_written,
  m.updated_membership_history,
  c.snapshot_year AS contact_snapshot_year,
  c.archived_row_count AS contact_rows_written
FROM membership_capture m
CROSS JOIN contact_capture c;`;
return [{ json: { ...config, sql } }];

const row = $input.first()?.json ?? {};
return [{
  json: {
    snapshot_key: row.snapshot_key,
    source_season: row.source_season,
    membership_rows_written: Number(row.membership_rows_written ?? 0),
    updated_membership_history: Boolean(row.updated_membership_history),
    contact_snapshot_year: Number(row.contact_snapshot_year ?? row.source_season ?? 0),
    contact_rows_written: Number(row.contact_rows_written ?? 0),
    captured_at: new Date().toISOString()
  }
}];
